import{_ as e,o as a,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"ROI Hub Overview","description":"","frontmatter":{"title":"ROI Hub Overview","slug":"roi-hub"},"headers":[],"relativePath":"marketer-hub/roi-hub.md","filePath":"marketer-hub/roi-hub.md"}'),n={name:"marketer-hub/roi-hub.md"};function s(i,t,d,c,h,l){return a(),r("div",null,[...t[0]||(t[0]=[o('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>ROI Hub is a critical tool in your marketing strategy if you&#39;re interested in analyzing and reporting on ad spend to make sure you&#39;re getting the best use of your investment dollars. ROI Hub unifies your cost data and revenue insights, and helps you understand the actual impact of your ad dollars.</p><p>ROI Hub also makes it easy to monitor the status of each of your ad partner connections, so you can find and fix issues quickly.</p><p>Currently, Branch supports over 20 of the largest and most commonly used ad partners. If we don&#39;t support a direct integration with an ad partner, you can still send their data to Branch via <a href="./cost-data-via-file-upload.html">file upload</a> or <a href="./cost-data-via-email-import.html">email import</a>.</p><h4 id="cost-data" tabindex="-1">Cost Data <a class="header-anchor" href="#cost-data" aria-label="Permalink to &quot;Cost Data&quot;">​</a></h4><p>Cost data is the amount of money spent on ad campaigns, and that value is required to make ad optimization decisions in the mobile marketing ecosystem. With ROI Hub, you can bring your cost data from across disparate ad partner sources together in one place within the Branch Dashboard.</p><h4 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to &quot;Access&quot;">​</a></h4><p>Access to ROI Hub requires a premium plan. Please <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">contact our Sales team</a> to learn more about pricing and availability.</p><h2 id="roi-hub-components" tabindex="-1">ROI Hub Components <a class="header-anchor" href="#roi-hub-components" aria-label="Permalink to &quot;ROI Hub Components&quot;">​</a></h2><p>The sections below describe the three tabs within the Branch Dashboard that come together to make ROI Hub.</p><h3 id="overview-1" tabindex="-1">Overview <a class="header-anchor" href="#overview-1" aria-label="Permalink to &quot;Overview&quot;">​</a></h3><p>For a quick look at which of your ad partners are getting significant traffic, as well as whether or not you have cost data ingestion set up for them, head to the <strong>Overview</strong> <a href="https://dashboard.branch.io/ads/roi-hub/overview" target="_blank" rel="noreferrer">tab</a> in ROI Hub.</p><p>The table featured in this tab includes columns for <strong>Ad Partner</strong>, <strong>Cost</strong>, <strong>Clicks</strong>, <strong>Installs</strong>, <strong>Opens</strong>, <strong>Status</strong>, and <strong>Actions</strong>.</p><p>If an ad partner has a status in the <strong>Status</strong> column, you can click on it to learn more. If there is an error associated with the connection, an error message with more information will be shared in the <strong>Error Message</strong> column.</p><h4 id="setup-cost-data" tabindex="-1">Setup Cost Data <a class="header-anchor" href="#setup-cost-data" aria-label="Permalink to &quot;Setup Cost Data&quot;">​</a></h4><p>Clicking the <strong>Setup cost data</strong> button under the <strong>Actions</strong> column will take you to the <strong>Ad Partner Settings</strong> page for that ad partner, where you can visit the <strong>Cost Data</strong> tab to set up <a href="./cost-data-via-api-connection.html">cost data ingestion via API connection</a> if an integration exists for that ad partner.</p><p>There are also two other ways import cost data into Branch: <a href="./cost-data-via-file-upload.html">file upload</a> or <a href="./cost-data-via-scheduled-ingestion.html">scheduled email import</a>.</p><h4 id="view-analytics" tabindex="-1">View Analytics <a class="header-anchor" href="#view-analytics" aria-label="Permalink to &quot;View Analytics&quot;">​</a></h4><p>Clicking the <strong>View Analytics</strong> button will take you to the <strong>Activity</strong> <a href="https://branch.dashboard.branch.io/ads/analytics/activity" target="_blank" rel="noreferrer">tab</a> in the <strong>Ads</strong> <a href="https://branch.dashboard.branch.io/ads/" target="_blank" rel="noreferrer">section</a> of the Branch Dashboard, where you can see tables for <strong>Trends</strong> and <strong>Events</strong> that allow you to compare by ad partner.</p><h3 id="connection-overview" tabindex="-1">Connection Overview <a class="header-anchor" href="#connection-overview" aria-label="Permalink to &quot;Connection Overview&quot;">​</a></h3><p>The <strong>Connection Overview</strong> <a href="https://branch.dashboard.branch.io/ads/roi-hub/connection-overview" target="_blank" rel="noreferrer">tab</a> of ROI Hub is a single place to manage all your cost-data connections.</p><p>This table view lets you sort your connections, easily identify issues, and routes you to fix problems with any connections.</p><p>.png)</p><table tabindex="0"><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td>Ad Partner</td><td>The name of the ad partner for the cost data connection.</td></tr><tr><td>Connection Name &amp; Account ID</td><td>The cost data connection name and ID for a given ad partner.</td></tr><tr><td>Last Pull</td><td>The most recent time and date that Branch requested cost data from a connection.</td></tr><tr><td>Last Successful Pull</td><td>The most recent time and date that Branch requested cost data from a connection and was able to receive cost data for a given connection.</td></tr><tr><td>Status</td><td>The status of the connection - Active, Inactive, Pending, or Failed.</td></tr><tr><td>Error Message</td><td>A description of what caused a connection to fail on the last cost data pull.</td></tr><tr><td>Actions</td><td>Click the <strong>Manage</strong> button to be taken to the <strong>Cost Data</strong> tab of the <strong>Ad Partner Settings</strong> page.</td></tr></tbody></table><p>Additionally, you can:</p><ul><li>Search by ad partner or connection name.</li><li>Filter by connection status.</li><li>Click the <strong>Add Cost Connection</strong> button on the top right of the page to route you to the Partner Management page to enable an ad partner.</li></ul><h3 id="import" tabindex="-1">Import <a class="header-anchor" href="#import" aria-label="Permalink to &quot;Import&quot;">​</a></h3><p>The <strong>Import</strong> <a href="https://dashboard.branch.io/ads/roi-hub/import" target="_blank" rel="noreferrer">tab</a> is where you can either <a href="./cost-data-via-file-upload.html">import files individually</a> under the <strong>File Upload</strong> view, or you can set up the files to be imported to Branch <a href="./cost-data-via-email-import.html">automatically through email</a> under the <strong>Email Importers</strong> view.</p><p>Both options are made simpler with the help of <a href="./templates-for-cost-data.html">cost data templates</a>, which you can create and store within this tab using the <strong>Cost data templates</strong> view.</p><p>You must create a cost data template for an ad partner <strong>before</strong> you can import cost data for them using file upload or email import.</p><p>The <strong>Import History</strong> view displays a record of previous imports that have taken place, either successfully or unsuccessfully. Clicking <strong>View</strong> in the <strong>Actions</strong> tab of this view will give you more information about that particular import, including error messages if the import failed.</p><h2 id="ad-partner-support" tabindex="-1">Ad Partner Support <a class="header-anchor" href="#ad-partner-support" aria-label="Permalink to &quot;Ad Partner Support&quot;">​</a></h2><p>ROI Hub currently supports the following ad partners for <a href="https://help.branch.io/docs/cost-data-via-api-connection#enabling-cost-via-api-connection" target="_blank" rel="noreferrer">sharing cost data with Branch via API connection</a>.</p><details><summary>Expand to see list of ad networks supported by direct API integration</summary><table tabindex="0"><thead><tr><th><strong>Ad Partner</strong></th><th>3p name</th></tr></thead><tbody><tr><td><a href="https://business.x.com/en/advertising" target="_blank" rel="noreferrer">Twitter</a></td><td><code>a_twitter</code></td></tr><tr><td><a href="https://www.adikteev.com/" target="_blank" rel="noreferrer">Adikteev</a></td><td><code>a_adikteev</code></td></tr><tr><td><a href="https://ads.apple.com/app-store" target="_blank" rel="noreferrer">Apple Ads</a></td><td><code>a_apple</code></td></tr><tr><td><a href="https://www.applovin.com/" target="_blank" rel="noreferrer">AppLovin</a></td><td><code>a_applovin</code></td></tr><tr><td><a href="https://www.auraads.us/" target="_blank" rel="noreferrer">Aura</a></td><td><code>a_aura</code></td></tr><tr><td><a href="https://www.criteo.com/" target="_blank" rel="noreferrer">Criteo</a></td><td><code>a_criteo</code></td></tr><tr><td><a href="https://business.google.com/us/google-ads/" target="_blank" rel="noreferrer">Google Ads</a></td><td><code>a_google_adwords</code></td></tr><tr><td><a href="https://marketingplatform.google.com/" target="_blank" rel="noreferrer">Google Marketing Platform (GMP)</a></td><td><code>a_google_marketing_platform</code></td></tr><tr><td><a href="https://advertising.inmobi.com/dsp" target="_blank" rel="noreferrer">InMobi DSP</a></td><td><code>a_inmobi_dsp</code></td></tr><tr><td><a href="https://www.jampp.com/" target="_blank" rel="noreferrer">Jampp</a></td><td><code>a_jampp</code></td></tr><tr><td><a href="https://liftoff.io/" target="_blank" rel="noreferrer">Liftoff</a></td><td><code>a_liftoff</code></td></tr><tr><td><a href="https://business.meta.com/" target="_blank" rel="noreferrer">Meta</a></td><td><code>a_facebook</code></td></tr><tr><td><a href="https://www.moloco.com/" target="_blank" rel="noreferrer">Moloco</a></td><td><code>a_moloco</code></td></tr><tr><td><a href="https://ads.pinterest.com/" target="_blank" rel="noreferrer">Pinterest</a></td><td><code>a_pinterest</code></td></tr><tr><td><a href="https://www.rtbhouse.com/" target="_blank" rel="noreferrer">RTBHouse</a></td><td><code>a_rtb_house_sa</code></td></tr><tr><td><a href="https://ads.snapchat.com/" target="_blank" rel="noreferrer">Snap</a></td><td><code>a_snap</code></td></tr><tr><td><a href="https://ads.tiktok.com/" target="_blank" rel="noreferrer">TikTok</a></td><td><code>a_tiktok</code></td></tr><tr><td><a href="https://unity.com/products/unity-ads" target="_blank" rel="noreferrer">Unity Ads</a></td><td><code>a_unity</code></td></tr><tr><td><a href="https://www.mintegral.com/" target="_blank" rel="noreferrer">Mintegral</a></td><td><code>a_mintegral</code></td></tr><tr><td><a href="https://www.remerge.io/" target="_blank" rel="noreferrer">Remerge</a></td><td><code>a_remerge</code></td></tr><tr><td><a href="https://smadex.com/" target="_blank" rel="noreferrer">Smadex</a></td><td><code>a_smadex</code></td></tr><tr><td><a href="https://youappi.com/" target="_blank" rel="noreferrer">YouAppi</a></td><td><code>a_youappi</code></td></tr><tr><td><a href="https://impact.com/" target="_blank" rel="noreferrer">Impact</a></td><td><code>a_impact</code></td></tr></tbody></table></details>',34)])])}const g=e(n,[["render",s]]);export{u as __pageData,g as default};
